// Utility: Validate index name
function isValidIndexName(index) {
  if (!index || typeof index !== 'string') return false;
  // Index names must be lowercase, cannot contain special characters that could be exploited
  const validPattern = /^[a-z0-9][a-z0-9_\-.*]*$/;
  // Prevent path traversal
  if (index.includes('..') || index.includes('/') || index.includes('\\')) return false;
  return validPattern.test(index) && index.length <= 255;
}

// Utility: Check for restricted/system indices
function isRestrictedIndex(index) {
  const restrictedPrefixes = ['.security', '.kibana_task_manager', '.apm-agent-configuration'];
  // Allow wildcard but block system indices
  if (index.startsWith('.')) {
    // Allow some common non-sensitive dot-prefixed indices if needed
    const allowedDotPrefixes = ['.ds-']; // data streams
    return !allowedDotPrefixes.some(prefix => index.startsWith(prefix));
  }
  return restrictedPrefixes.some(prefix => index.startsWith(prefix));
}

